var body = $input.first().json.body || $input.first().json;
if (!body.tenantId || !body.senderId || !body.messageText) return [];
if (body.platform !== 'telegram') return [];
return [{ json: {
  platform:'telegram', tenantId:body.tenantId,
  senderId:String(body.senderId), senderName:body.senderName||'Cliente',
  messageText:body.messageText, messageId:body.messageId||'',
  timestamp:body.timestamp||Date.now(),
  chatId:String(body.chatId||body.senderId), botToken:body.botToken||''
}}];

var msg=$('Normalizar Payload TG').first().json;
var tenant=$('Buscar Config Tenant').first().json;
var channel=$('Obtener Credenciales TG').first().json;
if(!channel||!channel.found) throw new Error('[TG] Canal no configurado para tenant '+msg.tenantId);
var bc=tenant.businessConfig||{}; var refs=tenant.references||[];
var tz=(bc.businessHours&&bc.businessHours.timezone)?bc.businessHours.timezone:'America/Bogota';
var now=new Date();
var localTime=new Intl.DateTimeFormat('es-CO',{timeZone:tz,hour:'2-digit',minute:'2-digit',hourCycle:'h23'}).format(now);
var dayName=new Intl.DateTimeFormat('es-CO',{timeZone:tz,weekday:'long'}).format(now);
var schedule=(bc.businessHours&&bc.businessHours.schedule)?bc.businessHours.schedule:[];
var todaySchedule=schedule.find(function(d){return (d.day||'').toLowerCase()===dayName.toLowerCase();});
var parts=localTime.split(':'); var nowMins=parseInt(parts[0],10)*60+parseInt(parts[1],10);
var inHours=true;
if(todaySchedule&&todaySchedule.isOpen){var op=(todaySchedule.open||'00:00').split(':');var cl=(todaySchedule.close||'23:59').split(':');inHours=nowMins>=(parseInt(op[0],10)*60+parseInt(op[1],10))&&nowMins<=(parseInt(cl[0],10)*60+parseInt(cl[1],10));}else if(todaySchedule&&!todaySchedule.isOpen){inHours=false;}
var catalogLines=(bc.catalog||[]).map(function(p){var l='- '+p.name;if(p.price)l+=' | $'+Number(p.price).toLocaleString('es-CO');if(p.category)l+=' | '+p.category;if(p.available===false)l+=' [NO DISPONIBLE]';if(p.description)l+=': '+p.description;return l;});
var faqLines=(bc.faq||[]).map(function(f){return 'P: '+f.question+'
R: '+f.answer;});
var refsText='';if(refs.length>0){refsText='

FUENTES DE REFERENCIA:
';refs.forEach(function(r){refsText+='- ['+r.type.toUpperCase()+'] '+r.name+': '+r.url;if(r.description)refsText+=' — '+r.description;refsText+='
';});}
var classInstr='INSTRUCCION CRITICA: Al FINAL de tu respuesta SIEMPRE agrega:
<JSON>
{"intent":"INTENT","confidence":SCORE}
</JSON>
INTENT: ventas|soporte|agendamiento|informacion|humano|fallback

';
var rawSys=classInstr+'=== INSTRUCCIONES DEL NEGOCIO ===
'+(bc.aiInstructions||'Eres un asistente de atencion al cliente profesional y amable.')+'

Negocio: '+(bc.businessName||'')+'
Canal: Telegram
Tono: '+(bc.tone||'amigable')+'

CATALOGO:
'+(catalogLines.length>0?catalogLines.join('
'):'Sin productos.')+'

FAQ:
'+(faqLines.length>0?faqLines.join('

'):'Sin FAQ.')+((bc.paymentMethods&&bc.paymentMethods.length>0)?'
Metodos de pago: '+bc.paymentMethods.join(', '):'')+refsText+'

Cliente: '+(msg.senderName||'Cliente');
var oe='{{';var ce='}}';
var systemMessage=rawSys.split('{').join(oe).split('}').join(ce);
// botToken: preferir el almacenado en canal, fallback al enviado por webhook
var botToken=channel.botToken||msg.botToken||'';
return [{json:{platform:'telegram',tenantId:msg.tenantId,senderId:msg.senderId,senderName:msg.senderName,message:msg.messageText,chatId:msg.chatId,botToken:botToken,inHours:inHours,outOfHoursMessage:bc.outOfHoursMessage||'Estamos fuera de horario. Te responderemos pronto.',systemMessage:systemMessage}}];

var ctx=$('Construir Contexto IA').first().json;
var output=$('Agente IA Telegram').first().json.output||'';
var clean=output.replace(/<JSON>[\s\S]*?<\/JSON>/g,'').trim();
// Telegram no soporta HTML complejo; limpiar tags que no sean básicos
clean=clean.replace(/<(?!\/?(?:b|i|u|s|code|pre|a\s))[^>]+>/gi,'');
return [{json:{platform:'telegram',tenantId:ctx.tenantId,senderId:ctx.senderId,senderName:ctx.senderName,messageText:ctx.message,responseText:clean,chatId:ctx.chatId,botToken:ctx.botToken}}];
